sys_script.script:
// Import the notification utility
var notificationUtil = new InsuranceNotificationUtils();

// Send notifications for policy status changes
if (current.status.changes() || current.isNewRecord()) {
    var status = current.getValue('status');

    if (status == 'active') {
        gs.addInfoMessage('Policy activated for client: ' + current.getValue('client_name'));
    } else if (status == 'cancelled') {
        gs.addInfoMessage('Policy cancelled for client: ' + current.getValue('client_name'));
        // Send notification about cancellation
        notificationUtil.sendPolicyExpiryNotification(current);
    }
}

// Check for policy expiry within 30 days
if (!current.policy_end_date.nil()) {
    var expiryDate = new GlideDateTime(current.getValue('policy_end_date'));
    var currentDate = new GlideDateTime();
    var thirtyDaysFromNow = new GlideDateTime(currentDate);
    thirtyDaysFromNow.addDaysLocalTime(30);

    if (expiryDate.compareTo(currentDate) > 0 && expiryDate.compareTo(thirtyDaysFromNow) <= 0) {
        notificationUtil.sendPolicyExpiryNotification(current);
    }
}
